import React, { useState } from "react";
import { Imgdb, Namedb } from "../components/firebase_setup";
import { v4 } from "uuid";
import { getDownloadURL, ref, uploadBytes } from "firebase/storage";
import { addDoc, collection } from "firebase/firestore";
import { useNavigate } from "react-router-dom";

function Home() {
  const [Txt, setTxt] = useState("");   // For text input
  const [img, setImg] = useState("");   // For image URL
  const [imgUploadComplete, setImgUploadComplete] = useState(false); // Track image upload status
  const navigate = useNavigate();

  const handleImgUpload = (e) => {
    const file = e.target.files[0];
    const imgRef = ref(Imgdb, `ImgsFile/${v4()}`); // Unique path in Firebase Storage

    uploadBytes(imgRef, file).then(snapshot => {
      getDownloadURL(snapshot.ref).then(url => {
        setImg(url);  // Set the image URL
        setImgUploadComplete(true); // Set upload status to complete
      }).catch(error => {
        console.error("Error getting download URL:", error);
      });
    }).catch(error => {
      console.error("Error uploading image:", error);
    });
  };

  const handleInput = async () => {
    if (imgUploadComplete) {  // Check if image is uploaded before saving to Firestore
      try {
        const email = localStorage.getItem("email");
        const docRef = collection(Namedb, "ProfileData");
        await addDoc(docRef, {
          txtval: Txt,      // Save text input
          imgUrl: img,       // Save image URL from Firebase Storage
          u_email: email     // Make sure to store the user's email as well
        });
        navigate("/feed");
      } catch (error) {
        console.error("Error writing document: ", error);
      }
    } else {
      console.log("Image upload not complete yet.");
    }
  };

  return (
    <div>
      <h1>This is the homepage for Catsa!</h1>
      <section>
        <input placeholder="Enter Name" onChange={(e) => setTxt(e.target.value)} /><br /><br />
        <input type="file" onChange={handleImgUpload} /><br /><br />
        <button onClick={handleInput}>Done!</button><br />
      </section>
    </div>
  );
}

export default Home;
